import numpy as np

def swish(x: np.ndarray) -> np.ndarray:
    return x / (1.0 + np.exp(-x))

def swiglu_ffn(x: np.ndarray, W_gate: np.ndarray, W_up: np.ndarray, W_down: np.ndarray, b_down: np.ndarray) -> np.ndarray:
    gate = swish(x @ W_gate)  # (seq_len, d_ff)
    up = x @ W_up             # (seq_len, d_ff)
    hidden = gate * up         # element-wise gating
    return hidden @ W_down + b_down
